input.command:
cat > /tmp/extract.py << 'EOF'
import sys
mods = []
try:
    import pypdf; mods.append('pypdf')
except Exception:
    try:
        import PyPDF2; mods.append('PyPDF2')
    except Exception:
        try:
            import fitz; mods.append('fitz')
        except Exception:
            mods.append('NONE')
print("MODULE:", mods[0])
m = mods[0]
for path in sys.argv[1:]:
    print("="*70)
    print("FILE:", path)
    try:
        if m == 'pypdf':
            from pypdf import PdfReader
            r = PdfReader(path)
            for i,p in enumerate(r.pages):
                t = p.extract_text() or ""
                print(f"--- page {i+1} ---"); print(t)
        elif m == 'PyPDF2':
            from PyPDF2 import PdfReader
            r = PdfReader(path)
            for i,p in enumerate(r.pages):
                t = p.extract_text() or ""
                print(f"--- page {i+1} ---"); print(t)
        else:
            import fitz
            d = fitz.open(path)
            for i in range(d.page_count):
                print(f"--- page {i+1} ---"); print(d[i].get_text())
    except Exception as e:
        print("ERROR:", e)
EOF
